package kingdom.smp.client;

import net.minecraft.ChatFormatting;
import net.minecraft.client.Minecraft;
import net.minecraft.client.gui.screens.inventory.AbstractContainerScreen;
import net.minecraft.client.gui.screens.inventory.BlastFurnaceScreen;
import net.minecraft.network.chat.Component;
import net.neoforged.bus.api.SubscribeEvent;
import net.neoforged.neoforge.client.event.ScreenEvent;
import org.lwjgl.glfw.GLFW;

/**
 * F4 / Tab / arrow / drag debug overlay for the Ironhold BlastFurnace reskin.
 * Generated by scripts/gen_gui_reskins.py.
 */
public final class BlastFurnaceSlotDebugHandler {
    private BlastFurnaceSlotDebugHandler() {}

    private static boolean isBlastFurnace(Object screen) {
        return screen instanceof BlastFurnaceScreen;
    }

    @SubscribeEvent
    public static void onKey(ScreenEvent.KeyPressed.Pre event) {
        if (!isBlastFurnace(event.getScreen())) return;
        int key = event.getKeyEvent().key();
        boolean shift = (event.getKeyEvent().modifiers() & GLFW.GLFW_MOD_SHIFT) != 0;

        if (key == GLFW.GLFW_KEY_F4) {
            BlastFurnaceSlotDebug.toggleEditMode();
            chat("§b[ironhold/blast_furnace] edit mode " + (BlastFurnaceSlotDebug.isEditMode() ? "ON" : "OFF"));
            event.setCanceled(true);
            return;
        }
        if (!BlastFurnaceSlotDebug.isEditMode()) return;
        int step = shift ? 5 : 1;
        switch (key) {
            case GLFW.GLFW_KEY_TAB -> { BlastFurnaceSlotDebug.cycleSelection(shift ? -1 : 1); chat(BlastFurnaceSlotDebug.summary()); }
            case GLFW.GLFW_KEY_LEFT  -> { BlastFurnaceSlotDebug.nudge(-step, 0); chat(BlastFurnaceSlotDebug.summary()); }
            case GLFW.GLFW_KEY_RIGHT -> { BlastFurnaceSlotDebug.nudge( step, 0); chat(BlastFurnaceSlotDebug.summary()); }
            case GLFW.GLFW_KEY_UP    -> { BlastFurnaceSlotDebug.nudge(0, -step); chat(BlastFurnaceSlotDebug.summary()); }
            case GLFW.GLFW_KEY_DOWN  -> { BlastFurnaceSlotDebug.nudge(0,  step); chat(BlastFurnaceSlotDebug.summary()); }
            case GLFW.GLFW_KEY_P -> {
                String dump = BlastFurnaceSlotDebug.printJava();
                System.out.println(dump);
                for (String line : dump.split("\n")) chat(line);
            }
            case GLFW.GLFW_KEY_R -> { BlastFurnaceSlotDebug.resetAll(); chat("§e[ironhold/blast_furnace] reset to defaults"); }
            default -> { return; }
        }
        event.setCanceled(true);
    }

    @SubscribeEvent
    public static void onMouseDown(ScreenEvent.MouseButtonPressed.Pre event) {
        if (!isBlastFurnace(event.getScreen())) return;
        if (!BlastFurnaceSlotDebug.isEditMode()) return;
        if (event.getMouseButtonEvent().button() != 0) return;
        AbstractContainerScreen<?> s = (AbstractContainerScreen<?>) event.getScreen();
        int mx = (int) event.getMouseX();
        int my = (int) event.getMouseY();
        if (BlastFurnaceSlotDebug.tryStartDrag(mx, my, s.getGuiLeft(), s.getGuiTop())) {
            event.setCanceled(true);
        }
    }

    @SubscribeEvent
    public static void onMouseDrag(ScreenEvent.MouseDragged.Pre event) {
        if (!isBlastFurnace(event.getScreen())) return;
        if (!BlastFurnaceSlotDebug.isDragging()) return;
        AbstractContainerScreen<?> s = (AbstractContainerScreen<?>) event.getScreen();
        int mx = (int) event.getMouseX();
        int my = (int) event.getMouseY();
        BlastFurnaceSlotDebug.updateDrag(mx, my, s.getGuiLeft(), s.getGuiTop());
        event.setCanceled(true);
    }

    @SubscribeEvent
    public static void onMouseUp(ScreenEvent.MouseButtonReleased.Pre event) {
        if (!isBlastFurnace(event.getScreen())) return;
        if (!BlastFurnaceSlotDebug.isDragging()) return;
        BlastFurnaceSlotDebug.endDrag();
        chat(BlastFurnaceSlotDebug.summary());
        event.setCanceled(true);
    }

    private static void chat(String msg) {
        Minecraft mc = Minecraft.getInstance();
        if (mc.player != null) mc.player.sendSystemMessage(Component.literal(msg).withStyle(ChatFormatting.AQUA));
    }
}
